let filtered = NetskopeWebTransactions_CL | where TimeGenerated {TimeRange} | where isnotempty(XTransactionId);
let total_rows = filtered | summarize total = count() | project total;
let duplicate_rows = filtered | summarize c = count() by XTransactionId | where c > 1 | summarize duplicates = sum(c - 1) | project duplicates;
print duplicate_percentage = 100.0 * toscalar(duplicate_rows) / toscalar(total_rows)

let filtered = NetskopeWebTransactions_CL | where TimeGenerated {TimeRange} | where isnotempty(XTransactionId);
let total_rows = filtered | summarize total = count();
let unique_rows = filtered | summarize by XTransactionId | count;
let duplicate_rows = filtered | summarize c = count() by XTransactionId | where c > 1 | summarize duplicates = sum(c - 1);
print 
    TotalRecords = toscalar(total_rows),
    UniqueTransactions = toscalar(unique_rows),
    DuplicateRecords = toscalar(duplicate_rows),
    DuplicatePercentage = round(100.0 * toscalar(duplicate_rows) / toscalar(total_rows), 2)
